#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    int id;
    char label[16];
} Item;

int main() {
    Item item;
    item.id = 42;
    strncpy(item.label, "core", sizeof(item.label));
    printf("%d\n", item.id);
    return 0;
}

